-template <typename T>
-typename std::enable_if <std::is_signed<T>::value, T>::type CeilDiv(T x, T y) {
-  if (y != 0 && x != 0) {
-    const T quotient = x / y;
-    return (x % y != 0 && ((x ^ y) >= 0)) ? (quotient + 1) : quotient;
-  }
-
-  return x;
-}
