-
-    auto *aDesc = context->GetInputDesc(INPUT_INDEX_A);
-    auto *aLogDesc = context->GetInputDesc(INPUT_INDEX_A_LOG);
-    auto *dtBiasDesc = context->GetInputDesc(INPUT_INDEX_DT_BIAS);
