-            else if (maxRPI >= 32)  { rowsPerIter = 32;  }
-            else if (maxRPI >= 16)  { rowsPerIter = 16;  }
-            else if (maxRPI >= 8)   { rowsPerIter = 8;   }
-            else if (maxRPI >= 4)   { rowsPerIter = 4;   }
-            else if (maxRPI >= 2)   { rowsPerIter = 2;   }
