-    const aclTensor *aLog, const aclTensor *a, const aclTensor *b,
-    const aclTensor *dtBias, float beta, float threshold,
-    aclTensor *g, aclTensor *betaOutput,
-    uint64_t *workspaceSize, aclOpExecutor **executor)
